import{_ as r,c as o,o as n,a as e,b as a}from"./app.426dd711.js";const v=JSON.parse('{"title":"7. Programaci\xF3n en Parejas (Pair Programming)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/pair-programming.md"}'),s={name:"practices/pair-programming.md"},i=e("h1",{id:"_7-programacion-en-parejas-pair-programming",tabindex:"-1"},[a("7. Programaci\xF3n en Parejas "),e("em",null,"(Pair Programming)"),a(),e("a",{class:"header-anchor",href:"#_7-programacion-en-parejas-pair-programming","aria-hidden":"true"},"#")],-1),d=e("blockquote",null,[e("p",null,"La programaci\xF3n del c\xF3digo se realizara en parejas, cada una utilizando un \xFAnico ordenador. As\xED, el c\xF3digo se revisa mientras se desarrolla. Se hace as\xED todo el tiempo posible y no solo cuando un programador necesite ayuda para realizar tal m\xE9todo o para averiguar la raz\xF3n de porqu\xE9 falla el c\xF3digo.")],-1),t=e("p",null,"De esta forma mientras uno desarrolla c\xF3digo el otro realiza una revisi\xF3n inmediata. Se evitar\xE1n la mayor\xEDa de los errores de programaci\xF3n debido a que habr\xE1 en todo momento una persona dedicada \xEDntegramente a buscar errores en tiempo de escritura del c\xF3digo. Adem\xE1s, la programaci\xF3n ser\xE1 mas fluida pues el desarrollador no tendr\xE1 que estar al tanto de encontrar sus errores ya que tendr\xE1 a su lado a otro programador que conocer\xE1 el dise\xF1o de lo que se esta programando y por lo tanto sabr\xE1 reconocer un error. Los desarrolladores permanecer\xE1n mas despejados durante el tiempo de trabajo y tambi\xE9n podr\xE1n ir intercambiando su rol, cada uno cumpliendo un rol diferente. Por ello, el c\xF3digo as\xED generado no contendr\xE1 errores sint\xE1cticos y posiblemente tampoco errores sem\xE1nticos y habr\xE1 sido realizado en un corto periodo de tiempo.",-1),l=e("p",null,"Las combinaciones y caracter\xEDsticas de este rol, no solo son variables, sino que adem\xE1s, son inmensas, permitiendo la libertad de \u201Cser originalmente creativos\u201D. Algunas de estas combinaciones (tal vez las m\xE1s frecuentes), suelen ser: - Uno escribe el c\xF3digo, mientras que otro lo va revisando; - Un programador m\xE1s avanzado, programa, mientras va explicando lo desarrollado a otro menos experto; - Los dos programadores piensan en como resolver el c\xF3digo, y uno de ellos lo escribe. De esa forma y seg\xFAn las necesidades de cada equipo, las funciones de cada programador, podr\xE1n variar ilimitadamente.",-1),c=[i,d,t,l];function m(p,u,g,_,b,h){return n(),o("div",null,c)}const y=r(s,[["render",m]]);export{v as __pageData,y as default};
